        'meta_title' => 'Bolinao Slow West Coast: Calm Two-Day Stop List | Resort Guru PH',
        'meta_description' => 'A calm two-day Bolinao stop list covering Saint James Church, Cape Bolinao Lighthouse, Patar Beach, the caves, the falls, and the UP Marine Lab.',
        'tags' => 'Bolinao, Pangasinan, West Coast, Slow Travel, Two Days',
        'cover_destination_key' => 'bolinao',
